import React, { useState } from 'react'

export default function TextForm(props) {

    const handleUpClick = () => {
        // console.log("Uppercase was clicked : " + text);
        let newText = text.toUpperCase();
        setText(newText);
    }

    const handleLowClick = () => {
        // console.log("Lowercase was clicked : " + text);
        let newText = text.toLowerCase();
        setText(newText);
    }

    const handleOnChange = (event) => {
        // console.log("On change");
        setText(event.target.value);
    }

    const handleClearClick = () => {
        // console.log("Clear was clicked : " + text);
        let newText = '';
        setText(newText);
    }
    // const speak = () => {
    //     let msg = new SpeechSynthesisUtterance();
    //     msg.text = text;
    //     window.speechSynthesis.speak(msg);
    // }

    const speak = () => {
    let msg = new SpeechSynthesisUtterance();
    msg.text = text;

    // સિસ્ટમમાં રહેલા બધા અવાજો મેળવો
    let voices = window.speechSynthesis.getVoices();

    // નામમાં 'Google US English' અથવા 'female' અથવા 'Zira' આવતું હોય તેવો અવાજ શોધો
    let femaleVoice = voices.find(voice => 
        voice.name.includes('Google US English') || 
        voice.name.includes('Zira') || 
        voice.name.toLowerCase().includes('female')
    );

    // જો છોકરીનો અવાજ મળે, તો તેને સેટ કરો
    if (femaleVoice) {
        msg.voice = femaleVoice;
    }

    window.speechSynthesis.speak(msg);
}


    const handleCopy = async () => {
        try {
            await navigator.clipboard.writeText(text);
            alert("Copied!");
        } catch (error) {
            console.error(error);
            alert("Failed to copy!");
        }
    };
    
    const [text, setText] = useState('');
    return (
        <>
            <div className='container'>
                <div className="mb-3">
                    <h1>{props.heading}</h1>
                    <textarea className="form-control" id="myBox" rows="8" onChange={handleOnChange} value={text}></textarea>
                </div>
                <button className="btn btn-primary mx-2" onClick={handleUpClick}>Convert to Uppercase</button>
                <button className="btn btn-primary mx-2" onClick={handleLowClick}>Convert to Lowercase</button>
                <button className="btn btn-primary mx-2" onClick={handleClearClick}>Clear Text</button>
                <button className="btn btn-primary mx-2" onClick={speak}>Speak</button>
                <button className="btn btn-primary mx-2" onClick={handleCopy}>Copy Text</button>


            </div>
            <div className="container my-3">
                <h1>Your Text Summary</h1>
                <p>{text.split(" ").length} word and {text.length} characters</p>
                <p>{0.008 * text.split(" ").length} minutes read</p>
                <h2>Preview</h2>
                <p>{text}</p>
            </div>
        </>

    )
}
